#include <stdio.h>
#define VELICINA 5

int main() {
    double niz[VELICINA], broj;
    int i=0, j;

    /* unos niza */
    while (i < VELICINA) {
        printf("Unesite %d. broj: \n", i + 1);
        scanf("%lf", &broj);

        if (broj == -1) {
            break;
        }

        if (broj <= 0) {
            printf("Broj mora biti pozitivan. Pokusajte ponovo.\n");
            continue;  // tražimo novi unos za isti indeks
        }

        niz[i] = broj;  // broj je validan, smjestimo ga u niz
        i++;
    }
    
    if (i == 0) {
        printf("Niz je prazan.");
        return 0;
    }


    printf("\nUneseni brojevi su: ");
    for (j = 0; j < i; j++) {
        printf("%.2f ", niz[j]);
    }

    return 0;
}
